  console.error(err);
  res.status(500).send("An internal server error occurred.");
});
```

---

### 7. **Secure Session Management (OWASP A3)**  
If your app uses sessions or cookies, make sure to set:

- `HttpOnly` for cookies
- `Secure` flag for cookies over HTTPS
- Use `SameSite` attribute

Example:

```js
res.cookie("session", "token", {
  httpOnly: true,
  secure: true,
  sameSite: 'strict',
});
```

